        emergency_projects.append({
            'Project_Name': project_name,
            'Funding_Source': funding_lookup[project_name]['Funding_Source'],
            'Amount': funding_lookup[project_name]['Amount'],
            'Status': 'Unknown',
            'Type': 'Unknown',
            'Topics': []
        })

